// Manages the internal app wallet balance and transactions.
// IMPORTANT: For production, the authoritative source of truth for wallet balance
// and transactions MUST be your secure backend server. This client-side implementation
// is for demonstration and immediate UI feedback only.
class WalletManager(private val context: Context, private val paymentApiService: PaymentApiService) {

    private val securePrefs: SharedPreferences by lazy {
        SecurityUtils.getEncryptedSharedPreferences(context)
    }

    private val _walletBalance = MutableStateFlow(0.0)
    val walletBalance: StateFlow<Double> = _walletBalance

    private val _transactions = MutableStateFlow<List<WalletTransaction>>(emptyList())
    val transactions: StateFlow<List<WalletTransaction>> = _transactions

    // Placeholder for current user ID, in a real app this would come from an auth module.
    private var currentUserId: String = "test_user_id"

    init {
        // Load initial balance from secure storage or fetch from backend
        // In a real app, always fetch from backend on app start for authoritative data.
        val storedBalance = securePrefs.getString("user_wallet_balance_$currentUserId", "0.0")?.toDoubleOrNull() ?: 0.0
        _walletBalance.value = storedBalance
        // Optionally load transactions here, or always fetch from backend
    }

    suspend fun refreshWalletBalance() {
        paymentApiService.getWalletBalance(currentUserId)?.let { balance ->
            _walletBalance.value = balance
            securePrefs.edit().putString("user_wallet_balance_$currentUserId", balance.toString()).apply()
        } ?: run {
            Log.e("WalletManager", "Failed to fetch wallet balance from backend.")
        }
    }

    // This method should primarily be called after a successful transaction (e.g., top-up)
    // and ideally confirmed by the backend.
    fun creditWallet(amount: Double, description: String = "Top-up"): Boolean {
        if (amount <= 0) return false
        val newBalance = _walletBalance.value + amount
        _walletBalance.value = newBalance
        securePrefs.edit().putString("user_wallet_balance_$currentUserId", newBalance.toString()).apply()

        val transaction = WalletTransaction(
            id = "wtxn_${System.currentTimeMillis()}",
            type = TransactionType.CREDIT,
            amount = amount,
            currency = "USD", // Or whatever your app's currency is
            timestamp = System.currentTimeMillis(),
            description = description
        )
        addTransaction(transaction)
        // IMPORTANT: In a real app, also send this to your backend via paymentApiService
        return true
    }

    // This method should primarily be called for purchases using wallet balance
    // and ideally confirmed by the backend.
    fun debitWallet(amount: Double, description: String = "In-app purchase"): Boolean {
        if (amount <= 0 || _walletBalance.value < amount) return false

        val newBalance = _walletBalance.value - amount
        _walletBalance.value = newBalance
        securePrefs.edit().putString("user_wallet_balance_$currentUserId", newBalance.toString()).apply()

        val transaction = WalletTransaction(
            id = "wtxn_${System.currentTimeMillis()}",
            type = TransactionType.DEBIT,
            amount = amount,
            currency = "USD",
            timestamp = System.currentTimeMillis(),
            description = description
        )
        addTransaction(transaction)
        // IMPORTANT: In a real app, also send this to your backend via paymentApiService
        return true
    }

    private fun addTransaction(transaction: WalletTransaction) {
        _transactions.value = _transactions.value + transaction
        // In a real app, transactions would typically be fetched from backend.
        // For local storage, you'd serialize and store the list.
    }

    // You would add methods to fetch transaction history from the backend here.
    suspend fun fetchTransactionHistory() {
        // Example:
        // val history = paymentApiService.getWalletTransactionHistory(currentUserId)
        // _transactions.value = history
    }
}


// GooglePlayBillingManager.kt
class GooglePlayBillingManager(
    private val context: Context,
    private val lifecycleScope: LifecycleCoroutineScope,
    private val paymentApiService: PaymentApiService
) : PurchasesUpdatedListener, BillingClientStateListener {

    private val TAG = "GooglePlayBillingManager"

    private lateinit var billingClient: BillingClient

    private val _products = MutableStateFlow<List<ProductInfo>>(emptyList())
    val products: StateFlow<List<ProductInfo>> = _products

    private val _purchases = MutableStateFlow<List<Purchase>>(emptyList())
    val purchases: StateFlow<List<Purchase>> = _purchases

    private val _purchaseEvents = MutableStateFlow<PurchaseResult?>(null)
    val purchaseEvents: StateFlow<PurchaseResult?> = _purchaseEvents

    init {
        setupBillingClient()
    }

    private fun setupBillingClient() {
        billingClient = BillingClient.newBuilder(context)
            .setListener(this)
            .enablePendingPurchases()
            .build()
        connectToGooglePlayBilling()
    }

    fun connectToGooglePlayBilling() {
        if (!billingClient.isReady) {
            Log.d(TAG, "Connecting to Google Play Billing...")
            billingClient.startConnection(this)
        }
    }

    override fun onBillingSetupFinished(billingResult: BillingResult) {
        if (billingResult.responseCode == BillingClient.BillingResponseCode.OK) {
            Log.d(TAG, "Google Play Billing setup finished successfully.")
            queryProducts()
            queryPurchases()
        } else {
            Log.e(TAG, "Google Play Billing setup failed: ${billingResult.debugMessage}")
        }
    }

    override fun onBillingServiceDisconnected() {
        Log.w(TAG, "Google Play Billing service disconnected. Retrying connection...")
        // Try to restart the connection on a delay
        lifecycleScope.launch {
            kotlinx.coroutines.delay(3000)
            connectToGooglePlayBilling()
        }
    }

    private fun queryProducts() {
        lifecycleScope.launch {
            val productList = listOf(
                QueryProductDetailsParams.Product.newBuilder()
                    .setProductId("premium_feature_unlock")
                    .setProductType(BillingClient.ProductType.INAPP)
                    .build(),
                QueryProductDetailsParams.Product.newBuilder()
                    .setProductId("gold_coins_100")
                    .setProductType(BillingClient.ProductType.INAPP)
                    .build(),
                QueryProductDetailsParams.Product.newBuilder()
                    .setProductId("monthly_subscription")
                    .setProductType(BillingClient.ProductType.SUBS)
                    .build()
            )

            val params = QueryProductDetailsParams.newBuilder().setProductList(productList).build()

            billingClient.queryProductDetails(params) { billingResult, productDetailsList ->
                if (billingResult.responseCode == BillingClient.BillingResponseCode.OK) {
                    val productsInfo = productDetailsList.mapNotNull { productDetails ->
                        val priceOffer = productDetails.oneTimePurchaseOfferDetails
                        val subscriptionOffer = productDetails.subscriptionOfferDetails?.firstOrNull() // Get first offer
                        val priceString = priceOffer?.formattedPrice ?: subscriptionOffer?.pricingPhases?.pricingPhaseList?.firstOrNull()?.formattedPrice ?: "N/A"

                        // Map ProductDetails to our simpler ProductInfo
                        ProductInfo(
                            productId = productDetails.productId,
                            name = productDetails.name,
                            description = productDetails.description,
                            price = priceString,
                            productType = if (productDetails.productType == BillingClient.ProductType.INAPP) Product.ProductType.INAPP else Product.ProductType.SUBS
                        )
                    }
                    _products.value = productsInfo
                    Log.d(TAG, "Queried products: ${_products.value.size}")
                } else {
                    Log.e(TAG, "Failed to query product details: ${billingResult.debugMessage}")
                }
            }
        }
    }

    fun queryPurchases() {
        lifecycleScope.launch {
            val inAppPurchasesResult = billingClient.queryPurchasesAsync(
                QueryPurchasesParams.newBuilder().setProductType(BillingClient.ProductType.INAPP).build()
            )
            val subsPurchasesResult = billingClient.queryPurchasesAsync(
                QueryPurchasesParams.newBuilder().setProductType(BillingClient.ProductType.SUBS).build()
            )

            val combinedPurchases = mutableListOf<Purchase>()

            if (inAppPurchasesResult.billingResult.responseCode == BillingClient.BillingResponseCode.OK) {
                combinedPurchases.addAll(inAppPurchasesResult.purchasesList)
            } else {
                Log.e(TAG, "Failed to query in-app purchases: ${inAppPurchasesResult.billingResult.debugMessage}")
            }

            if (subsPurchasesResult.billingResult.responseCode == BillingClient.BillingResponseCode.OK) {
                combinedPurchases.addAll(subsPurchasesResult.purchasesList)
            } else {
                Log.e(TAG, "Failed to query subscriptions: ${subsPurchasesResult.billingResult.debugMessage}")
            }

            _purchases.value = combinedPurchases
            Log.d(TAG, "Queried existing purchases: ${_purchases.value.size}")
            processPendingPurchases(combinedPurchases)
        }
    }

    fun initiatePurchase(activity: Activity, productId: String, productType: Product.ProductType) {
        lifecycleScope.launch {
            val productList = listOf(
                QueryProductDetailsParams.Product.newBuilder()
                    .setProductId(productId)
                    .setProductType(if (productType == Product.ProductType.INAPP) BillingClient.ProductType.INAPP else BillingClient.ProductType.SUBS)
                    .build()
            )
            val params = QueryProductDetailsParams.newBuilder().setProductList(productList).build()

            val (billingResult, productDetailsList) = billingClient.queryProductDetails(params)

            if (billingResult.responseCode == BillingClient.BillingResponseCode.OK && productDetailsList != null && productDetailsList.isNotEmpty()) {
                val productDetails = productDetailsList.first()

                val productDetailsParamsList = when (productDetails.productType) {
                    BillingClient.ProductType.INAPP -> {
                        listOf(
                            BillingFlowParams.ProductDetailsParams.newBuilder()
                                .setProductDetails(productDetails)
                                .build()
                        )
                    }
                    BillingClient.ProductType.SUBS -> {
                        val offerToken = productDetails.subscriptionOfferDetails?.firstOrNull()?.offerToken
                        if (offerToken != null) {
                            listOf(
                                BillingFlowParams.ProductDetailsParams.newBuilder()
                                    .setProductDetails(productDetails)
                                    .setOfferToken(offerToken)
                                    .build()
                            )
                        } else {
                            Log.e(TAG, "No subscription offer found for product: $productId")
                            _purchaseEvents.value = PurchaseResult(success = false, errorMessage = "No subscription offer available.")
                            return@launch
                        }
                    }
                    else -> {
                        Log.e(TAG, "Unsupported product type: ${productDetails.productType}")
                        _purchaseEvents.value = PurchaseResult(success = false, errorMessage = "Unsupported product type.")
                        return@launch
                    }
                }

                val flowParams = BillingFlowParams.newBuilder()
                    .setProductDetailsParamsList(productDetailsParamsList)
                    .build()

                billingClient.launchBillingFlow(activity, flowParams)
            } else {
                Log.e(TAG, "Failed to find product details for $productId: ${billingResult.debugMessage}")
                _purchaseEvents.value = PurchaseResult(success = false, errorMessage = "Product not found or billing error.")
            }
        }
    }


    override fun onPurchasesUpdated(billingResult: BillingResult, purchases: MutableList<Purchase>?) {
        if (billingResult.responseCode == BillingClient.BillingResponseCode.OK && purchases != null) {
            Log.d(TAG, "Purchases updated. Count: ${purchases.size}")
            _purchases.value = purchases
            processPendingPurchases(purchases)
        } else if (billingResult.responseCode == BillingClient.BillingResponseCode.USER_CANCELED) {
            Log.d(TAG, "Purchase canceled by user.")
            _purchaseEvents.value = PurchaseResult(success = false, errorMessage = "Purchase canceled.")
        } else {
            Log.e(TAG, "Purchase error: ${billingResult.debugMessage}")
            _purchaseEvents.value = PurchaseResult(success = false, errorMessage = "Purchase failed: ${billingResult.debugMessage}")
        }
    }

    private fun processPendingPurchases(purchases: List<Purchase>) {
        lifecycleScope.launch {
            for (purchase in purchases) {
                if (purchase.purchaseState == Purchase.PurchaseState.PURCHASED) {
                    // Purchase is successful, now verify and acknowledge/consume
                    if (!purchase.isAcknowledged) {
                        handlePurchase(purchase)
                    } else {
                        Log.d(TAG, "Purchase ${purchase.orderId} already acknowledged.")
                        // If already acknowledged, but not yet processed by the app (e.g., app crashed)
                        // you might want to re-grant entitlement here.
                        _purchaseEvents.value = PurchaseResult(
                            success = true,
                            transactionId = purchase.orderId,
                            purchaseToken = purchase.purchaseToken,
                            orderId = purchase.orderId
                        )
                    }
                } else if (purchase.purchaseState == Purchase.PurchaseState.PENDING) {
                    Log.d(TAG, "Purchase ${purchase.orderId} is PENDING. It requires further action from the user.")
                    // Inform user to complete the purchase (e.g., in Google Play app)
                    _purchaseEvents.value = PurchaseResult(success = false, errorMessage = "Purchase is pending user action.")
                }
            }
        }
    }

    private suspend fun handlePurchase(purchase: Purchase) {
        val productIds = purchase.products // For Billing v5+, a purchase can have multiple product IDs
        if (productIds.isEmpty()) {
            Log.e(TAG, "Purchase has no associated product IDs: ${purchase.orderId}")
            _purchaseEvents.value = PurchaseResult(success = false, errorMessage = "Purchase has no associated product IDs.")
            return
        }

        val primaryProductId = productIds.first() // Assuming one product per purchase for simplicity

        Log.d(TAG, "Handling purchase: ${purchase.orderId} for product: $primaryProductId")

        // 1. Send purchase details to your backend for server-side verification
        val isVerified = paymentApiService.verifyGooglePlayPurchase(
            purchase.purchaseToken,
            primaryProductId,
            purchase.orderId
        )

        if (isVerified) {
            Log.d(TAG, "Purchase ${purchase.orderId} successfully verified by backend.")

            // 2. Grant entitlement to the user (e.g., unlock feature, add coins)
            // (This logic would likely be in your WalletManager or user entitlement system)

            if (Product.ProductType.INAPP == findProductType(primaryProductId)) { // Assuming it's a consumable
                // 3. Consume the purchase if it's a consumable item
                val consumeParams = ConsumeParams.newBuilder()
                    .setPurchaseToken(purchase.purchaseToken)
                    .build()

                val consumeResult = billingClient.consumePurchase(consumeParams)

                if (consumeResult.billingResult.responseCode == BillingClient.BillingResponseCode.OK) {
                    Log.d(TAG, "Purchase ${purchase.orderId} consumed successfully.")
                    // 4. Notify backend of consumption
                    paymentApiService.notifyGooglePlayConsumption(purchase.purchaseToken)
                    _purchaseEvents.value = PurchaseResult(
                        success = true,
                        transactionId = purchase.orderId,
                        purchaseToken = purchase.purchaseToken,
                        orderId = purchase.orderId
                    )
                } else {
                    Log.e(TAG, "Failed to consume purchase ${purchase.orderId}: ${consumeResult.billingResult.debugMessage}")
                    _purchaseEvents.value = PurchaseResult(success = false, errorMessage = "Failed to consume purchase.")
                }
            } else { // It's a non-consumable or subscription, just acknowledge
                // 3. Acknowledge the purchase
                val acknowledgePurchaseParams = AcknowledgePurchaseParams.newBuilder()
                    .setPurchaseToken(purchase.purchaseToken)
                    .build()

                val ackResult = billingClient.acknowledgePurchase(acknowledgePurchaseParams)

                if (ackResult.responseCode == BillingClient.BillingResponseCode.OK) {
                    Log.d(TAG, "Purchase ${purchase.orderId} acknowledged successfully.")
                    // 4. Notify backend of acknowledgement (if needed, or backend knows from verification)
                    _purchaseEvents.value = PurchaseResult(
                        success = true,
                        transactionId = purchase.orderId,
                        purchaseToken = purchase.purchaseToken,
                        orderId = purchase.orderId
                    )
                } else {
                    Log.e(TAG, "Failed to acknowledge purchase ${purchase.orderId}: ${ackResult.debugMessage}")
                    _purchaseEvents.value = PurchaseResult(success = false, errorMessage = "Failed to acknowledge purchase.")
                }
            }
        } else {
            Log.e(TAG, "Backend verification failed for purchase: ${purchase.orderId}. Not acknowledging/consuming.")
            _purchaseEvents.value = PurchaseResult(success = false, errorMessage = "Purchase verification failed.")
        }
    }

    private fun findProductType(productId: String): Product.ProductType? {
        // This is a simplified lookup. In a real app, you'd have a mapping
        // or fetch from your backend.
        // For example, if "gold_coins_100" is always consumable.
        return when (productId) {
            "gold_coins_100" -> Product.ProductType.INAPP
            "premium_feature_unlock" -> Product.ProductType.INAPP // If it's a permanent unlock, it's non-consumable INAPP
            "monthly_subscription" -> Product.ProductType.SUBS
            else -> null // Unknown type, handle accordingly
        }
    }
}


// PaymentProcessor.kt
// This class orchestrates all payment-related operations.
class PaymentProcessor(
    private val context: Context,
    private val lifecycleScope: LifecycleCoroutineScope,
    private val paymentApiService: PaymentApiService,
    private val walletManager: WalletManager
) {
    private val googlePlayBillingManager = GooglePlayBillingManager(context, lifecycleScope, paymentApiService)

    val googlePlayProducts: StateFlow<List<ProductInfo>> = googlePlayBillingManager.products
    val googlePlayPurchases: StateFlow<List<Purchase>> = googlePlayBillingManager.purchases
    val googlePlayPurchaseEvents: StateFlow<PurchaseResult?> = googlePlayBillingManager.purchaseEvents

    val walletBalance: StateFlow<Double> = walletManager.walletBalance
    val walletTransactions: StateFlow<List<WalletTransaction>> = walletManager.transactions

    // Call this from your Application class or main Activity
    fun initialize() {
        Log.d("PaymentProcessor", "Initializing PaymentProcessor...")
        googlePlayBillingManager.connectToGooglePlayBilling()
        lifecycleScope.launch {
            walletManager.refreshWalletBalance()
        }
    }

    // --- Google Play Billing (In-App Purchases / Subscriptions) ---

    // Expose Google Play products directly
    fun getGooglePlayProducts(): StateFlow<List<ProductInfo>> = googlePlayProducts

    fun purchaseGooglePlayProduct(activity: Activity, productId: String, productType: Product.ProductType) {
        googlePlayBillingManager.initiatePurchase(activity, productId, productType)
    }

    // Call this to consume a purchased item (e.g., after user has received in-game currency)
    // Note: The GooglePlayBillingManager handles consumption automatically after verification
    // for consumable INAPP items. This method might be for specific scenarios or to re-trigger.
    // suspend fun consumeGooglePlayPurchase(purchaseToken: String): Boolean {
    //    return googlePlayBillingManager.consumePurchase(purchaseToken)
    // }

    // --- Wallet Management ---

    fun getWalletBalanceFlow(): StateFlow<List<WalletTransaction>> = walletTransactions
    fun getWalletTransactionsFlow(): StateFlow<Double> = walletBalance

    suspend fun refreshWalletBalance() {
        walletManager.refreshWalletBalance()
    }

    // Top up wallet using Google Play IAP (e.g., user buys "100 Gold Coins" which adds to wallet)
    // This is handled by the GooglePlayBillingManager and then the WalletManager is updated
    // after successful verification and consumption. No direct method needed here.

    // Purchase an in-app item using wallet balance
    suspend fun purchaseWithWallet(amount: Double, description: String): PurchaseResult {
        if (walletManager.debitWallet(amount, description)) {
            // IMPORTANT: In a real app, this debit action MUST be confirmed by your backend.
            // Simulate sending to backend.
            val transaction = WalletTransaction(
                id = "local_wtxn_${System.currentTimeMillis()}",
                type = TransactionType.DEBIT,
                amount = amount,
                currency = "USD", // Match your app's currency
                timestamp = System.currentTimeMillis(),
                description = description
            )
            val success = paymentApiService.recordWalletTransaction("current_user_id", transaction) // Replace with actual user ID

            if (success) {
                return PurchaseResult(success = true, transactionId = transaction.id, errorMessage = null)
            } else {
                // If backend recording failed, attempt to revert local wallet state or handle error.
                // This is a complex rollback scenario, for simplicity, we just log here.
                Log.e("PaymentProcessor", "Failed to record wallet transaction on backend for amount: $amount, description: $description")
                // Revert local debit if backend failed is crucial for consistency.
                walletManager.creditWallet(amount, "Revert failed purchase of: $description") // Simple revert
                return PurchaseResult(success = false, errorMessage = "Failed to record transaction on server.")
            }
        } else {
            return PurchaseResult(success = false, errorMessage = "Insufficient wallet balance or invalid amount.")
        }
    }

    // --- External Payment Gateway (e.g., credit card via Stripe/PayPal) ---
    // This assumes you have a UI component (e.g., Stripe's CardInputWidget)
    // that gathers card details and tokenizes them client-side.
    // The resulting token is then sent to your backend.

    suspend fun processExternalPayment(
        userId: String,
        amount: Double,
        currency: String,
        paymentMethodToken: PaymentMethodToken,
        description: String
    ): PurchaseResult {
        val transactionId = paymentApiService.processTokenizedPayment(
            userId, amount, currency, paymentMethodToken, description
        )

        return if (transactionId != null) {
            PurchaseResult(success = true, transactionId = transactionId)
        } else {
            PurchaseResult(success = false, errorMessage = "External payment failed.")
        }
    }
}

